import os
path = r"D:\benchmark\audio\acm_mm_competition_2026"

# 查看 train 下第一个目录的结构
train_sample = os.path.join(path, "train", "000000")
print("=== train/000000/ 结构 ===")
if os.path.exists(train_sample):
    for item in sorted(os.listdir(train_sample)):
        full = os.path.join(train_sample, item)
        if os.path.isdir(full):
            print(f"  [DIR]  {item}/")
            # 再看二级目录
            for sub in sorted(os.listdir(full))[:10]:
                sub_full = os.path.join(full, sub)
                if os.path.isdir(sub_full):
                    print(f"    [DIR]  {sub}/")
                else:
                    print(f"    [FILE] {sub}")
        else:
            size = os.path.getsize(full)
            print(f"  [FILE] {item} ({size} bytes)")

print("\n\n=== test/ 完整列表 ===")
